sql:
SELECT region_id, SUM(deaths) AS total_deaths
FROM region_statistics
GROUP BY region_id;

SELECT date, infected, exposed, active, recovered, deaths
FROM covid_statistics
WHERE region_id = 1;

external_knowledge:
- 'bustling hubs' refers to regions with populations over 1 million;
- 'shadow of sorrow' metaphorically represents the highest number of deaths in these regions;
- 'urban giants' refers to large populated regions;
- 'weight of their burden' indicates the impact or toll of deaths per million people;

sql:
SELECT user_name
FROM users
WHERE role > 0;

SELECT message
FROM notifications
WHERE message LIKE '%update%';

SELECT MAX(infected) AS max_infected
FROM covid_statistics
WHERE date LIKE '2020-07%';

SELECT region_id, AVG(deaths) AS average_deaths_per_region
FROM covid_statistics
GROUP BY region_id;

external_knowledge:
- 'places' refers to regions;
- 'total number of vaccinated people' can be calculated by summing the number of vaccinated individuals per region;
- 'place names' refer to the names of the regions.
